from flask import Flask, request, jsonify
import pickle
import os

app = Flask(__name__)

# Load pre-trained model
pretrained_model_path = 'pretrained_model.pkl'
try:
    with open(pretrained_model_path, 'rb') as f:
        pretrained_model = pickle.load(f)
except FileNotFoundError:
    pretrained_model = None

@app.route('/upload', methods=['POST'])
def upload_model():
    if request.method == 'POST':
        model_file = request.files['model']
        model_name = request.form.get('name')
        
        # Save the uploaded model to a temporary location
        temp_dir = '/tmp/models'
        os.makedirs(temp_dir, exist_ok=True)
        model_path = os.path.join(temp_dir, f'{model_name}.pkl')
        model_file.save(model_path)
        
        try:
            with open(model_path, 'rb') as f:
                custom_model = pickle.load(f)
                
            # Load the uploaded model and use it for inference
            # Use a secure technique to prevent ml unsafe deserialization
            # Here we're using a whitelist approach to load only specific classes
            allowed_classes = ['LinearRegression', 'DecisionTreeClassifier']
            if isinstance(custom_model, type) and custom_model.__name__ in allowed_classes:
                return jsonify({'message': f'Model {model_name} loaded successfully'}), 200
            else:
                return jsonify({'error': 'Invalid model type'}), 400
        except Exception as e:
            return jsonify({'error': str(e)}), 500
        
    return jsonify({'error': 'Invalid request method'}), 405

if __name__ == '__main__':
    app.run(debug=True)